import{_ as a,r as i,o as l,e as c,l as e,x as t,w as n,F as d,E as r,g as s}from"./app.a050b316.js";var g="/images/channelConfig/messenger/test.png",h="/images/channelConfig/messenger/add-messenger.png",p="/images/channelConfig/messenger/access-token.png",u="/images/channelConfig/messenger/add-channel.png",f="/images/channelConfig/messenger/config-webhook.png";const m={},b=r('<h1 id="messenger" tabindex="-1"><a class="header-anchor" href="#messenger" aria-hidden="true">#</a> Messenger</h1><div class="custom-container right"><p><img src="'+g+'" alt="test"></p></div><p>The <a href="https://developers.facebook.com/docs/messenger-platform/introduction" target="_blank" rel="noopener noreferrer">Messenger Platform</a> is meant for businesses to handle inquiries from their customers. Using the Facebook Messenger integration, you can create a Facebook Messenger bot to interact with your end-users within your business.</p><p>We are going to show here how to configure the Framely integration and Messenger and then, deploy the chatbot to a Framely hosted environment. For the private deployment, please consult systems in your organization.</p><p>Follow these steps to configure:</p>',5),k={class:"table-of-contents"},v=s("Before You Begin"),y=s("Set Up Messenger"),_=s("Add Messenger Channel"),w=s("Configure Webhook"),C=s("Test Your Chatbot"),M=r('<h2 id="before-you-begin" tabindex="-1"><a class="header-anchor" href="#before-you-begin" aria-hidden="true">#</a> Before You Begin</h2><p>On the Messenger side, please ensure you have all of the following:</p><ul><li><strong>Facebook Page</strong>: A Facebook Page will be used as the identity of your Messenger experience. To create a new Page, visit <a href="https://www.facebook.com/pages/create" target="_blank" rel="noopener noreferrer">Create a Page</a>.</li><li><strong>Developer Account</strong>: Your developer account is required to create new apps. To create a new developer account, go to the <a href="https://developers.facebook.com/" target="_blank" rel="noopener noreferrer">Meta Developers</a> website and click the &#39;Get Started&#39; button.</li><li><strong>Facebook App</strong>: The Facebook app contains the settings for your Messenger experience, including access tokens. To create a new app, visit your <a href="https://developers.facebook.com/apps" target="_blank" rel="noopener noreferrer">app dashboard</a> and click on &#39;Create App&#39; in the top right corner.</li></ul><h2 id="set-up-messenger" tabindex="-1"><a class="header-anchor" href="#set-up-messenger" aria-hidden="true">#</a> Set Up Messenger</h2><ol><li>Visit your <a href="https://developers.facebook.com/apps" target="_blank" rel="noopener noreferrer">app dashboard</a> and enter one of the apps you want to serve by Framely chatbot. On the left sidebar, click <strong>Add Product</strong>. Hover over <strong>Messenger</strong> and Click <strong>Set Up</strong>.</li></ol><p><img src="'+h+'" alt="add-messenger"></p><ol start="2"><li>Click <strong>Add or Remove Pages</strong> and select a page you want to subscribe your app to.</li><li>In the <strong>Access Tokens</strong> section, click <strong>Generate Token</strong> button. \u{1F4CB} Copy the access token, it&#39;s needed when <a href="#add-messenger-channel">adding Messenger channel</a>.</li></ol><p><img src="'+p+'" alt="access-token"></p><h2 id="add-messenger-channel" tabindex="-1"><a class="header-anchor" href="#add-messenger-channel" aria-hidden="true">#</a> Add Messenger Channel</h2><ol><li>On the Framely side, enter a chatbot that you want to deploy. Click <strong>Setting</strong> &gt; <strong>Integrations</strong>. In the <strong>Channels</strong> field, click <strong>Add New</strong> &gt; <strong>Facebook Messenger</strong>.</li><li>The configuration information is as follows. Once you complete the configuration, click <strong>SAVE</strong>. <ul><li><strong>Name</strong>: You can set a name for your Facebook Messenger. This will be part of the Callback URL.</li><li><strong>Callback URL</strong>: \u{1F4CB} Copy this value. This will be used to configure the Facebook Messenger Webhook.</li><li><strong>Verify Token</strong>: You can enter any private token you desire. \u{1F4CB} Copy this value. This will be used to configure the Facebook Messenger Webhook.</li><li><strong>Page Access Token</strong>: Enter the access token generated during the <a href="#set-up-messenger">Messenger setup</a>.</li></ul></li><li>Click <strong>Deploy</strong> on the right sidebar to deploy your chatbot.</li></ol><p><img src="'+u+'" alt="add-channel"></p><h2 id="configure-webhook" tabindex="-1"><a class="header-anchor" href="#configure-webhook" aria-hidden="true">#</a> Configure Webhook</h2><ol><li>On the Messenger side, in the <strong>Webhooks</strong> section of the Messenger settings console, click <strong>Add Callback URL</strong> button.</li><li>Paste the <em>Callback URL</em> and <em>Verify Token</em> values you copied when <a href="#add-messenger-channel">adding the Messenger channel</a>. Click <strong>Verify and Save</strong> to confirm you callback URL.</li><li>Click <strong>Add subscriptions</strong> and enable <code>messages</code> and <code>messaging_postbacks</code> in the page subscriptions.</li></ol><p><img src="'+f+'" alt="config-webhook"></p><div class="custom-container tip"><p class="custom-container-title">Note</p><p>For now, we can only allow one access token on one channel, which means that you need to configure different Facebook apps for different Facebook pages.</p></div><h2 id="test-your-chatbot" tabindex="-1"><a class="header-anchor" href="#test-your-chatbot" aria-hidden="true">#</a> Test Your Chatbot</h2><ol><li>To test that your app setup was successful, go to your page and send a message to yourself. If you get a response, you have fully set up your app for receiving messages! \u{1F389}</li><li>To make the app accessible to the public, switch to <a href="https://developers.facebook.com/docs/development/build-and-test/app-modes#live-mode" target="_blank" rel="noopener noreferrer">live mode</a>.</li></ol><div class="custom-container tip"><p class="custom-container-title">Two app modes in Facebook apps</p><ul><li>In the <a href="https://developers.facebook.com/docs/development/build-and-test/app-modes#development-mode" target="_blank" rel="noopener noreferrer">development mode</a>, only the administrator and tester that you invited can access the app. In this case, talk to the chatbot.</li><li>In the <a href="https://developers.facebook.com/docs/development/build-and-test/app-modes#live-mode" target="_blank" rel="noopener noreferrer">live mode</a>, apps can request <a href="https://developers.facebook.com/docs/permissions/reference" target="_blank" rel="noopener noreferrer">permissions</a> from anyone, but only permissions approved through <a href="https://developers.facebook.com/docs/app-review" target="_blank" rel="noopener noreferrer">App Review</a>. Click <a href="https://developers.facebook.com/docs/messenger-platform/app-review/" target="_blank" rel="noopener noreferrer">here</a> to submit your app for review.</li></ul></div>',18);function F(T,A){const o=i("RouterLink");return l(),c(d,null,[b,e("nav",k,[e("ul",null,[e("li",null,[t(o,{to:"#before-you-begin"},{default:n(()=>[v]),_:1})]),e("li",null,[t(o,{to:"#set-up-messenger"},{default:n(()=>[y]),_:1})]),e("li",null,[t(o,{to:"#add-messenger-channel"},{default:n(()=>[_]),_:1})]),e("li",null,[t(o,{to:"#configure-webhook"},{default:n(()=>[w]),_:1})]),e("li",null,[t(o,{to:"#test-your-chatbot"},{default:n(()=>[C]),_:1})])])]),M],64)}var P=a(m,[["render",F],["__file","messenger.html.vue"]]);export{P as default};
